using Microsoft.AspNetCore.Http.Features;

var builder = WebApplication.CreateBuilder(args);

// Raise the max request body size to 50 MB
builder.WebHost.ConfigureKestrel(options =>
{
    options.Limits.MaxRequestBodySize = 50 * 1024 * 1024;
});

var app = builder.Build();

app.MapPost("/upload", async (HttpRequest request) =>
{
    // Ensure it's a multipart form
    if (!request.HasFormContentType)
        return Results.BadRequest("Expected a multipart form request.");

    var form = await request.ReadFormAsync();

    var description = form["description"].ToString();
    var files = form.Files.GetFiles("images");

    if (files.Count == 0)
        return Results.BadRequest("No images provided.");

    var saved = new List<string>();

    foreach (var file in files)
    {
        if (!file.ContentType.StartsWith("image/"))
            continue;

        var fileName = $"{Guid.NewGuid()}{Path.GetExtension(file.FileName)}";
        var path = Path.Combine("uploads", fileName);

        Directory.CreateDirectory("uploads");

        await using var stream = File.Create(path);
        await file.CopyToAsync(stream);

        saved.Add(fileName);
    }

    return Results.Ok(new { description, uploadedFiles = saved });
})
.DisableAntiforgery()
.WithRequestFormLimits(multipartBodyLengthLimit: 50 * 1024 * 1024);

app.Run();
```

**Key points:**

- `ConfigureKestrel` raises the request body limit (default is ~30 MB).
- `.WithRequestFormLimits(...)` raises the multipart form limit to match.
- `form.Files.GetFiles("images")` retrieves all files submitted under the `images` field name.
- `.DisableAntiforgery()` is needed for minimal APIs that accept form data without an antiforgery token.

A matching `curl` test:

```bash
curl -X POST http://localhost:5000/upload \
  -F "description=My vacation photos" \
  -F "images=@photo1.jpg" \
  -F "images=@photo2.png"
```
